SELECT ?country ?countryLabel (SUM(?percentageNum) AS ?indigenousPercentage) ?lifeExpectancy
WHERE {
  # Latin American countries via Latin languages in Americas
  VALUES ?language { wd:Q1324 wd:Q5146 wd:Q150 } .
  ?country wdt:P31/wdt:P279* wd:Q6256 ;
          wdt:P37 ?language ;
          wdt:P30/wdt:P279* wd:Q15 ;
          rdfs:label ?countryLabel ;
          wdt:P2230 ?lifeExpectancy .
  FILTER(LANG(?countryLabel) = "en") .

  # Amerindian percentage via ethnic group
  ?country p:P172 ?stmt .
  ?stmt ps:P172 ?ethnicGroup ;
        pq:P2175 ?percentageRaw .
  ?ethnicGroup wdt:P31/wdt:P279* wd:Q206598 .

  # Clean numeric percentage
  BIND(REPLACE(STR(?percentageRaw), "[^0-9.]+", "") AS ?cleanPerc)
  FILTER(STRENDS(?percentageRaw, "%") || CONTAINS(?cleanPerc, "."))
  BIND(xsd:decimal(?cleanPerc) AS ?percentageNum)
}
GROUP BY ?country ?countryLabel ?lifeExpectancy
ORDER BY DESC(?lifeExpectancy)

